import { useEffect, useState } from "react";
import axios from "axios";
import Navbar from "../components/Navbar";
import Footer from "../components/Footer";

export default function CustomerDashboard() {

  const user = JSON.parse(localStorage.getItem("user"));

  const [workers, setWorkers] = useState([]);
  const [search, setSearch] = useState("");

  const [date, setDate] = useState("");
  const [time, setTime] = useState("");

  const [myJobs, setMyJobs] = useState([]);

  useEffect(() => {

    axios
      .get("http://localhost:5000/api/auth/workers")
      .then(res => setWorkers(res.data));

    axios
      .get(`http://localhost:5000/api/jobs/customer/${user._id}`)
      .then(res => setMyJobs(res.data));

  }, []);

  const filteredWorkers = workers.filter(worker =>
    worker.skills
      ?.join(" ")
      .toLowerCase()
      .includes(search.toLowerCase())
  );

  const bookWorker = async (worker) => {

    await axios.post(
      "http://localhost:5000/api/jobs/create",
      {
        customerId: user._id,
        customerName: user.name,

        labourId: worker._id,
        labourName: worker.name,

        workType: worker.skills?.join(", "),

        customerDate: date,
        customerTime: time
      }
    );

    alert("Request Sent");

    window.location.reload();
  };

  const acceptDeal = async (id) => {

    await axios.put(
      `http://localhost:5000/api/jobs/customer-accept/${id}`
    );

    window.location.reload();
  };

  const rejectDeal = async (id) => {

    await axios.put(
      `http://localhost:5000/api/jobs/customer-reject/${id}`
    );

    window.location.reload();
  };

  return (
    <div style={styles.page}>

      <Navbar />

      <div style={styles.container}>

        <h1 style={styles.heading}>
          Find Workers
        </h1>

        <input
          style={styles.search}
          placeholder="Search Worker Type..."
          onChange={(e) => setSearch(e.target.value)}
        />

        <div style={styles.dateBox}>

          <input
            type="date"
            style={styles.input}
            onChange={(e) => setDate(e.target.value)}
          />

          <input
            placeholder="Preferred Time"
            style={styles.input}
            onChange={(e) => setTime(e.target.value)}
          />

        </div>

        <div style={styles.grid}>

          {filteredWorkers.map(worker => (

            <div key={worker._id} style={styles.card}>

              <div style={styles.top}>

                <div style={styles.avatar}>
                  {worker.name.charAt(0)}
                </div>

                <div>

                  <h2>{worker.name}</h2>

                  <p style={styles.role}>
                    Professional Worker
                  </p>

                </div>

              </div>

              <div style={styles.skillWrap}>

                {worker.skills?.map((skill, index) => (

                  <span key={index} style={styles.skill}>
                    {skill}
                  </span>

                ))}

              </div>

              <button
                style={styles.bookBtn}
                onClick={() => bookWorker(worker)}
              >
                Send Request
              </button>

            </div>
          ))}

        </div>

        <h1 style={styles.bookingHeading}>
          My Requests
        </h1>

        <div style={styles.grid}>

          {myJobs.map(job => (

            <div key={job._id} style={styles.card}>

              <h2>{job.labourName}</h2>

              <p>
                <strong>Work:</strong> {job.workType}
              </p>

              <p>
                <strong>Date:</strong> {job.customerDate}
              </p>

              <p>
                <strong>Your Time:</strong> {job.customerTime}
              </p>

              <p>
                <strong>Labour Status:</strong> {job.labourStatus}
              </p>

              {job.labourStatus === "accepted" && (

                <>
                  <p>
                    <strong>Labour Price:</strong>
                    ₹ {job.labourPrice}
                  </p>

                  <p>
                    <strong>Labour Time:</strong>
                    {job.labourPreferredTime}
                  </p>

                  <div style={styles.btnRow}>

                    <button
                      style={styles.acceptBtn}
                      onClick={() => acceptDeal(job._id)}
                    >
                      Accept
                    </button>

                    <button
                      style={styles.rejectBtn}
                      onClick={() => rejectDeal(job._id)}
                    >
                      Reject
                    </button>

                  </div>
                </>
              )}

              <p>
                <strong>Final Status:</strong>
                {job.customerFinalStatus}
              </p>

            </div>
          ))}

        </div>

      </div>

      <Footer />

    </div>
  );
}

const styles = {

  page: {
    background: "#f4f7fb",
    minHeight: "100vh",
    fontFamily: "Arial"
  },

  container: {
    padding: "40px"
  },

  heading: {
    fontSize: "40px",
    marginBottom: "20px"
  },

  search: {
    width: "350px",
    padding: "14px",
    borderRadius: "10px",
    border: "1px solid #ddd"
  },

  dateBox: {
    display: "flex",
    gap: "15px",
    marginTop: "20px",
    marginBottom: "30px"
  },

  input: {
    padding: "14px",
    borderRadius: "10px",
    border: "1px solid #ddd"
  },

  grid: {
    display: "grid",
    gridTemplateColumns: "repeat(auto-fit,minmax(320px,1fr))",
    gap: "20px"
  },

  card: {
    background: "white",
    padding: "25px",
    borderRadius: "18px",
    boxShadow: "0 8px 20px rgba(0,0,0,0.08)"
  },

  top: {
    display: "flex",
    gap: "15px",
    alignItems: "center"
  },

  avatar: {
    width: "60px",
    height: "60px",
    borderRadius: "50%",
    background: "#2563eb",
    color: "white",
    display: "flex",
    justifyContent: "center",
    alignItems: "center",
    fontSize: "24px"
  },

  role: {
    color: "#6b7280"
  },

  skillWrap: {
    display: "flex",
    flexWrap: "wrap",
    gap: "10px",
    marginTop: "20px"
  },

  skill: {
    background: "#e0edff",
    color: "#2563eb",
    padding: "8px 12px",
    borderRadius: "20px"
  },

  bookBtn: {
    width: "100%",
    marginTop: "25px",
    background: "#2563eb",
    color: "white",
    border: "none",
    padding: "14px",
    borderRadius: "10px"
  },

  bookingHeading: {
    marginTop: "60px",
    marginBottom: "20px"
  },

  btnRow: {
    display: "flex",
    gap: "15px",
    marginTop: "20px"
  },

  acceptBtn: {
    flex: 1,
    background: "#22c55e",
    color: "white",
    border: "none",
    padding: "12px",
    borderRadius: "10px"
  },

  rejectBtn: {
    flex: 1,
    background: "#ef4444",
    color: "white",
    border: "none",
    padding: "12px",
    borderRadius: "10px"
  }
};
